-- Retry pattern for deadlock victim (error 1205)
BEGIN TRY
  BEGIN TRAN;
    UPDATE A SET x = 1 WHERE Id = 1;
    UPDATE B SET y = 2 WHERE Id = 1;
  COMMIT;
END TRY
BEGIN CATCH
  IF ERROR_NUMBER() = 1205 ROLLBACK; -- caller retries
  ELSE THROW;
END CATCH;

